namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private readonly List<Notification> _notifications;
    private int _nextId;

    public NotificationService()
    {
        _notifications = new List<Notification>
        {
            new(1, "Welcome to the app!", DateTime.UtcNow.AddMinutes(-10)),
            new(2, "Your profile was updated.", DateTime.UtcNow.AddMinutes(-7)),
            new(3, "New feature available: dark mode.", DateTime.UtcNow.AddMinutes(-3)),
        };
        _nextId = 4;
    }

    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_notifications)
        {
            return Task.FromResult(_notifications.ToList());
        }
    }

    public Task<List<Notification>> GetNotificationsSinceAsync(int lastId)
    {
        // Simulate new notifications arriving occasionally
        lock (_notifications)
        {
            if (Random.Shared.Next(3) == 0) // ~1 in 3 chance each poll
            {
                var id = _nextId++;
                _notifications.Add(new Notification(
                    id,
                    $"New event #{id} occurred.",
                    DateTime.UtcNow));
            }

            var newer = _notifications.Where(n => n.Id > lastId).ToList();
            return Task.FromResult(newer);
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject NotificationsApp.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@_notifications.Count</span></h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item">
                <strong>@n.Message</strong>
                <small class="text-muted ms-2">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<NotificationsApp.Services.Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastId;

    protected override async Task OnInitializedAsync()
    {
        // Runs during prerender AND when interactive — loads initial data once.
        _notifications = await NotificationService.GetNotificationsAsync();
        _lastId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires when the component is live/interactive,
            // never during static SSR prerender. Safe to start polling here.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);
                var newer = await NotificationService.GetNotificationsSinceAsync(_lastId);
                if (newer.Count > 0)
                {
                    _notifications.AddRange(newer);
                    _lastId = newer.Max(n => n.Id);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (TaskCanceledException)
            {
                break;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

